diff --git a/lib/node_modules/@stdlib/stats/base/stdevwd/lib/ndarray.js b/lib/node_modules/@stdlib/stats/base/stdevwd/lib/ndarray.js
index f31809bdc91..922c515634e 100644
--- a/lib/node_modules/@stdlib/stats/base/stdevwd/lib/ndarray.js
+++ b/lib/node_modules/@stdlib/stats/base/stdevwd/lib/ndarray.js
@@ -20,8 +20,9 @@

 // MODULES //

-var variancewd = require( '@stdlib/stats/strided/variancewd' ).ndarray;
 var sqrt = require( '@stdlib/math/base/special/sqrt' );
+var arraylike2object = require( '@stdlib/array/base/arraylike2object' );
+var accessors = require( './accessors.js' );


 // MAIN //
@@ -29,6 +30,40 @@ var sqrt = require( '@stdlib/math/base/special/sqrt' );
 /**
 * Computes the standard deviation of a strided array using Welford's algorithm.
 *
+* ## Method
+*
+* -   This implementation uses Welford's algorithm for efficient computation, which can be derived as follows. Let
+*
+*     ```tex
+*     \begin{align*}
+*     S_n &= n \sigma_n^2 \\
+*         &= \sum_{i=1}^{n} (x_i - \mu_n)^2 \\
+*         &= \biggl(\sum_{i=1}^{n} x_i^2 \biggr) - n\mu_n^2
+*     \end{align*}
+*     ```
+*
+*     Accordingly,
+*
+*     ```tex
+*     \begin{align*}
+*     S_n - S_{n-1} &= \sum_{i=1}^{n} x_i^2 - n\mu_n^2 - \sum_{i=1}^{n-1} x_i^2 + (n-1)\mu_{n-1}^2 \\
+*                   &= x_n^2 - n\mu_n^2 + (n-1)\mu_{n-1}^2 \\
+*                   &= x_n^2 - \mu_{n-1}^2 + n(\mu_{n-1}^2 - \mu_n^2) \\
+*                   &= x_n^2 - \mu_{n-1}^2 + n(\mu_{n-1} - \mu_n)(\mu_{n-1} + \mu_n) \\
+*                   &= x_n^2 - \mu_{n-1}^2 + (\mu_{n-1} - x_n)(\mu_{n-1} + \mu_n) \\
+*                   &= x_n^2 - \mu_{n-1}^2 + \mu_{n-1}^2 - x_n\mu_n - x_n\mu_{n-1} + \mu_n\mu_{n-1} \\
+*                   &= x_n^2 - x_n\mu_n - x_n\mu_{n-1} + \mu_n\mu_{n-1} \\
+*                   &= (x_n - \mu_{n-1})(x_n - \mu_n) \\
+*                   &= S_{n-1} + (x_n - \mu_{n-1})(x_n - \mu_n)
+*     \end{align*}
+*     ```
+*
+*     where we use the identity
+*
+*     ```tex
+*     x_n - \mu_{n-1} = n (\mu_n - \mu_{n-1})
+*     ```
+*
 * ## References
 *
 * -   Welford, B. P. 1962. "Note on a Method for Calculating Corrected Sums of Squares and Products." _Technometrics_ 4 (3). Taylor & Francis: 419–20. doi:[10.1080/00401706.1962.10490022](https://doi.org/10.1080/00401706.1962.10490022).
@@ -51,7 +86,37 @@ var sqrt = require( '@stdlib/math/base/special/sqrt' );
 * // returns 2.5
 */
 function stdevwd( N, correction, x, stride, offset ) {
-	return sqrt( variancewd( N, correction, x, stride, offset ) );
+	var delta;
+	var mu;
+	var M2;
+	var ix;
+	var o;
+	var v;
+	var n;
+	var i;
+
+	n = N - correction;
+	if ( N <= 0 || n <= 0.0 ) {
+		return NaN;
+	}
+	if ( N === 1 || stride === 0 ) {
+		return 0.0;
+	}
+	o = arraylike2object( x );
+	if ( o.accessorProtocol ) {
+		return accessors( N, correction, o, stride, offset );
+	}
+	ix = offset;
+	M2 = 0.0;
+	mu = 0.0;
+	for ( i = 0; i < N; i++ ) {
+		v = x[ ix ];
+		delta = v - mu;
+		mu += delta / (i+1);
+		M2 += delta * ( v - mu );
+		ix += stride;
+	}
+	return sqrt( M2 / n );
 }


