'use strict';

/**
* Compute the standard deviation of a strided array using Welford's algorithm.
*
* @module @stdlib/stats/base/stdevwd
*
* @example
* var stdevwd = require( '@stdlib/stats/base/stdevwd' );
*
* var x = [ 1.0, -2.0, 2.0 ];
*
* var v = stdevwd( x.length, 1, x, 1 );
* // returns ~2.0817
*
* @example
* var floor = require( '@stdlib/math/base/special/floor' );
* var stdevwd = require( '@stdlib/stats/base/stdevwd' );
*
* var x = [ 2.0, 1.0, 2.0, -2.0, -2.0, 2.0, 3.0, 4.0 ];
* var N = floor( x.length / 2 );
*
* var v = stdevwd.ndarray( N, 1, x, 2, 1 );
* // returns 2.5
*/

// MODULES //

var main = require( './main.js' );


// EXPORTS //

module.exports = main;

// exports: { "ndarray": "main.ndarray" }

/**
